/**
 * 将可能会渲染为disabled态表单元素打上标记；
 * 用于 tooltip识别这些子元素，防止 mouseenter,mouseleave这些事件无法触发
 */
export type DisabledableComp<T> = T & {
  /**
   * @internal
   */
  __DISABLEDABLE_FORM_COMP: true;
};

export function markAsDisabledableComp<T>(ele: T): DisabledableComp<T> {
  return Object.defineProperty(ele, '__DISABLEDABLE_FORM_COMP', {
    value: true,
    configurable: false,
    writable: false,
  }) as DisabledableComp<T>;
}

export function isDisabledableComp<T>(ele: DisabledableComp<T>): boolean {
  return Boolean(ele?.__DISABLEDABLE_FORM_COMP);
}
